<script setup lang="ts">import { computed, onMounted, ref } from 'vue'; import { archiveItem, getItem } from '../api/catalog'; import type { ItemDefinition } from '../catalog/catalogModels'; import StPageHeader from '../components/StPageHeader.vue'; const props=defineProps<{itemId:string;role:string}>(); const item=ref<ItemDefinition>(); const canWrite=computed(()=>props.role!=='VIEWER'); onMounted(async()=>item.value=await getItem(props.itemId)); async function archive(){if(item.value&&confirm('确认归档此物品？'))item.value=await archiveItem(item.value.id,item.value.version)}</script>
<template><article v-if="item"><StPageHeader :title="item.name" eyebrow="物品详情"><template v-if="canWrite" #actions><button @click="archive">归档物品</button></template></StPageHeader><dl><dt>单位</dt><dd>{{ item.defaultUnit }}</dd><dt>条码</dt><dd><span v-for="code in item.barcodes" :key="code">{{ code }}</span></dd><dt>标签</dt><dd><span v-for="tag in item.tags" :key="tag">{{ tag }}</span></dd></dl></article><p v-else>正在加载物品...</p></template>
